const weatherData = {
    "Beijing": { temp: 5, condition: "Sunny", humidity: 30, wind: "North 3" },
    "Shanghai": { temp: 12, condition: "Cloudy", humidity: 65, wind: "East 2" },
  };
  const city = $input.item.json.city || "Beijing";
  const weather = weatherData[city] || { temp: 15, condition: "Unknown", humidity: 50, wind: "Breeze" };

  return JSON.stringify({ city, ...weather, updated_at: new Date().toISOString() });

const query = $input.first().json.input || $input.first().json.query || "unknown";                   

  return {                                                                                             
    json: {                                                                                            
      response: JSON.stringify({                                                                       
        query: query,                                                                                  
        results: [                                                                                     
          { title: "Search result 1", snippet: "This is a simulated search result for: " + query },    
          { title: "Search result 2", snippet: "Another result about: " + query }                      
        ],                                                                                             
        note: "This is a simulated search - not real web results"                                      
      })                                                                                               
    }                                                                                                  
  };

const expression = $input.first().json.input || $input.first().json.expression || "0";                                                                                                                    
let result;                                                                                          
try {                                                                                                

  result = eval(expression);                                                                         
} catch (e) {                                                                                        
  result = "Error: Invalid expression";                                                              
}                                                                                                    

return {                                                                                             
  json: {                                                                                            
    response: JSON.stringify({                                                                       
      expression: expression,                                                                        
      result: result                                                                                 
    })                                                                                               
  }                                                                                                  
};
